css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #0a0e1a; color: white; }
.layout { display: flex; min-height: 100vh; }
.sidebar { width: 220px; background: #0f1320; border-right: 1px solid rgba(255,255,255,0.06); padding: 28px 18px; flex-shrink: 0; }
.logo { font-size: 18px; font-weight: 800; margin-bottom: 32px; padding-left: 8px; }
nav { display: flex; flex-direction: column; gap: 4px; }
nav a { display: flex; align-items: center; gap: 12px; padding: 11px 12px; border-radius: 10px; color: rgba(255,255,255,0.5); font-size: 14px; font-weight: 600; cursor: pointer; text-decoration: none; }
nav a span { font-size: 16px; }
nav a.active { background: rgba(234,179,8,0.12); color: #facc15; }
.content { flex: 1; padding: 32px 36px; max-width: 1100px; }
header { display: flex; justify-content: space-between; align-items: flex-end; margin-bottom: 22px; flex-wrap: wrap; gap: 12px; }
header h1 { font-size: 26px; font-weight: 800; }
header p { color: rgba(255,255,255,0.4); font-size: 13px; margin-top: 4px; }
.period { display: flex; gap: 4px; background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.07); border-radius: 10px; padding: 4px; }
.period button { background: transparent; border: none; color: rgba(255,255,255,0.5); padding: 8px 14px; border-radius: 8px; font-size: 12.5px; font-weight: 700; cursor: pointer; }
.period button.active { background: rgba(234,179,8,0.15); color: #facc15; }
.balance-card { background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.07); border-radius: 18px; padding: 24px; display: flex; justify-content: space-between; align-items: center; gap: 24px; margin-bottom: 22px; flex-wrap: wrap; }
.balance-left { display: flex; flex-direction: column; gap: 6px; }
.balance-left .label { color: rgba(255,255,255,0.45); font-size: 12.5px; font-weight: 600; }
.balance-left .value { font-size: 32px; font-weight: 800; }
.balance-chart { flex: 1; min-width: 200px; max-width: 320px; height: 80px; }
.balance-chart svg { width: 100%; height: 100%; }
.stats { display: grid; grid-template-columns: repeat(auto-fit, minmax(180px, 1fr)); gap: 14px; margin-bottom: 22px; }
.stat { background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.07); border-radius: 16px; padding: 18px 20px; display: flex; align-items: center; gap: 12px; position: relative; }
.stat .icon { font-size: 22px; }
.stat .value { display: block; font-size: 16px; font-weight: 800; }
.stat .label { display: block; color: rgba(255,255,255,0.4); font-size: 12px; font-weight: 600; }
.delta { position: absolute; top: 16px; right: 16px; font-size: 11px; font-weight: 700; padding: 2px 8px; border-radius: 999px; }
.delta.up { color: #4ade80; background: rgba(74,222,128,0.12); }
.delta.down { color: #f87171; background: rgba(248,113,113,0.12); }
.panel { background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.07); border-radius: 18px; padding: 22px; }
.panel-head { display: flex; justify-content: space-between; align-items: center; margin-bottom: 18px; }
.panel-head h2 { font-size: 15px; font-weight: 700; }
.badge { background: rgba(234,179,8,0.12); color: #facc15; font-size: 11px; font-weight: 700; padding: 4px 10px; border-radius: 999px; }
table { width: 100%; border-collapse: collapse; }
th { text-align: left; font-size: 11.5px; color: rgba(255,255,255,0.4); font-weight: 700; text-transform: uppercase; letter-spacing: 0.05em; padding: 0 0 12px; }
td { padding: 12px 0; font-size: 13.5px; border-top: 1px solid rgba(255,255,255,0.05); }
.coin { font-weight: 600; }
.up { color: #4ade80; font-weight: 700; }
.down { color: #f87171; font-weight: 700; }
.flat { color: rgba(255,255,255,0.4); font-weight: 700; }
@media (max-width: 800px) { .layout { flex-direction: column; } .sidebar { width: 100%; display: flex; } nav { flex-direction: row; overflow-x: auto; } }

